const recipes = $json.recipes;

return recipes.map(recipe => ({
  json: {
    ...recipe,
    createdAt: new Date().toISOString()
  }
}));

const headers = $json.headers ?? {};
const forwardedFor = headers['x-forwarded-for'];

const rawIp =
  headers['cf-connecting-ip'] ||
  headers['x-real-ip'] ||
  (forwardedFor ? forwardedFor.split(',')[0] : '') ||
  '127.0.0.1';

const ip = rawIp.trim().replace(/^::ffff:/, '');

const date = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'Europe/Berlin'
}).format(new Date());

return [{
  json: {
    ...$json,
    ip,
    date,
    requestTime: Date.now(),
    quotaKey: `${date}|${ip}`,
    globalQuotaKey: `${date}|GLOBAL`
  }
}];

const request = $('IP und Datum').first().json;

const rows = $input.all()
  .map(item => item.json)
  .filter(row => row.quotaKey);

const ipRow = rows.find(
  row => row.quotaKey === request.quotaKey
);

const globalRow = rows.find(
  row => row.quotaKey === request.globalQuotaKey
);

return [{
  json: {
    ...request,

    ipCount: Number(ipRow?.count ?? 0),
    globalCount: Number(globalRow?.count ?? 0),

    lastRequest: Number(ipRow?.lastRequest ?? 0),

    ipRowExists: Boolean(ipRow),
    globalRowExists: Boolean(globalRow)
  }
}];

const data = $input.first().json;

return [
  {
    json: {
      quotaKey: data.quotaKey,
      ip: data.ip,
      date: data.date,
      count: Number(data.ipCount ?? 0) + 1,
      lastRequest: Number(data.requestTime)
    }
  },
  {
    json: {
      quotaKey: data.globalQuotaKey,
      ip: '',
      date: data.date,
      count: Number(data.globalCount ?? 0) + 1,
      lastRequest: Number(data.requestTime)
    }
  }
];

const output = $input.first().json.output;

const cleanedOutput = output
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/, '')
  .trim();

const parsed = JSON.parse(cleanedOutput);

return [
  {
    json: parsed
  }
]
